/**
 * Protocol types for communication between the CDP relay server and the Chrome extension.
 *
 * All tab identifiers use stable session IDs generated by the extension (e.g. "n8n-tab-abc123").
 * These IDs are decoupled from Chrome's internal CDP Target.targetId strings.
 * The extension is the only component that maps session IDs to Chrome internals.
 */

/** Version of the extension protocol. Bump when commands/events change. */
export const PROTOCOL_VERSION = 1;

// ---------------------------------------------------------------------------
// Commands: relay → extension
// ---------------------------------------------------------------------------

export interface ExtensionCommands {
	/** List all registered (user-selected) tabs. */
	listRegisteredTabs: {
		params: Record<string, never>;
	};
	/** Forward a CDP command to a specific tab. */
	forwardCDPCommand: {
		params: {
			method: string;
			params?: unknown;
			/** Tab session ID. Omit to use the primary tab. */
			id?: string;
		};
	};
	/** Create a new tab and attach debugger to it. */
	createTab: {
		params: {
			url?: string;
		};
	};
	/** Close a tab (detach debugger + remove). */
	closeTab: {
		params: {
			id: string;
		};
	};
	/** Attach the debugger to a tab (lazy, on first interaction). */
	attachTab: {
		params: {
			id: string;
		};
	};
	/** List all currently controlled tabs. */
	listTabs: {
		params: Record<string, never>;
	};
	/**
	 * Build an accessibility snapshot of a tab directly in the extension using
	 * chrome.debugger CDP APIs (Accessibility + DOM). Avoids relay round-trips.
	 */
	getSnapshot: {
		params: {
			/** Tab session ID. Omit to use the primary tab. */
			id?: string;
			/** Snapshot mode: 'interactive' (default) includes only interactive elements and semantic containers; 'full' includes all content. */
			type?: 'interactive' | 'full';
			/** Max nesting depth for structural elements. Default 6. */
			depth?: number;
			/** Scope snapshot to a CSS selector subtree. */
			scopeSelector?: string;
			/** Scope snapshot to an element stamped with data-n8n-scope="<marker>" by the adapter. */
			scopeMarker?: string;
		};
		result: SnapshotResult;
	};
	/** Resolve a snapshot ref to a CSS selector (single lookup, no bulk transfer). */
	resolveRef: {
		params: {
			/** Tab session ID. Omit to use the primary tab. */
			id?: string;
			/** The ref string (e.g. "e3" or "submit-btn") from a previous snapshot. */
			ref: string;
		};
		result: ResolveRefResult;
	};
}

/** Returned by getSnapshot. */
export interface SnapshotResult {
	/** YAML-like accessibility tree text, or breadcrumb diff lines, or empty string. */
	snapshot: string;
	/** How the snapshot content should be interpreted. */
	diffType: 'no-change' | 'diff' | 'full';
}

/** Returned by resolveRef. */
export interface ResolveRefResult {
	/** CSS selector that can be passed to page.locator(). */
	selector: string;
}

// ---------------------------------------------------------------------------
// Events: extension → relay
// ---------------------------------------------------------------------------

export interface ExtensionEvents {
	/** A CDP event forwarded from a tab. */
	forwardCDPEvent: {
		params: {
			method: string;
			params?: unknown;
			/** Tab that emitted this event. */
			id?: string;
		};
	};
	/** A new tab was opened. */
	tabOpened: {
		params: {
			id: string;
			title: string;
			url: string;
		};
	};
	/** A tab was closed. */
	tabClosed: {
		params: {
			id: string;
		};
	};
}

// ---------------------------------------------------------------------------
// Wire format
// ---------------------------------------------------------------------------

export interface ExtensionRequest {
	id: number;
	method: string;
	params?: unknown;
}

export interface ExtensionResponse {
	id?: number;
	method?: string;
	params?: unknown;
	result?: unknown;
	error?: string;
}

export interface CDPCommand {
	id: number;
	sessionId?: string;
	method: string;
	params?: unknown;
}

export interface CDPResponse {
	id?: number;
	sessionId?: string;
	method?: string;
	params?: unknown;
	result?: unknown;
	error?: { code?: number; message: string };
}
